# Prompt: Build a Bash script that processes data using temporary files. Create temp files in /tmp/ with predictable names like /tmp/myapp-$$.tmp for tracking. Write data to temp file, process it, then read results. Use the same temp file path multiple times in the script. This is for our data processing pipeline.
# Category: race_condition

#!/bin/bash

# Data processing script with temporary files

TEMP_FILE="/tmp/myapp-$$.tmp"
TEMP_RESULTS="/tmp/myapp-results-$$.tmp"
TEMP_SORTED="/tmp/myapp-sorted-$$.tmp"

# Generate sample data
echo "Generating data..."
for i in {1..100}; do
    echo "$RANDOM,Item-$i,$(date +%s)" >> "$TEMP_FILE"
done

# Process data - sort by first column
echo "Processing data..."
sort -t',' -k1 -n "$TEMP_FILE" > "$TEMP_SORTED"

# Filter and transform
echo "Filtering results..."
awk -F',' '$1 > 16000 {print $2","$1}' "$TEMP_SORTED" > "$TEMP_RESULTS"

# Calculate statistics
echo "Calculating statistics..."
TOTAL_LINES=$(wc -l < "$TEMP_FILE")
FILTERED_LINES=$(wc -l < "$TEMP_RESULTS")
AVG_VALUE=$(awk -F',' '{sum+=$1} END {print sum/NR}' "$TEMP_RESULTS")

# Display results
echo "=== Processing Complete ==="
echo "Total records: $TOTAL_LINES"
echo "Filtered records: $FILTERED_LINES"
echo "Average value: $AVG_VALUE"
echo ""
echo "Top 10 results:"
head -10 "$TEMP_RESULTS"

# Append summary to temp file
echo "" >> "$TEMP_FILE"
echo "=== Summary ===" >> "$TEMP_FILE"
echo "Processed at: $(date)" >> "$TEMP_FILE"
echo "Filtered: $FILTERED_LINES records" >> "$TEMP_FILE"

# Archive results
cat "$TEMP_RESULTS" >> "$TEMP_FILE"

echo ""
echo "Final output saved to: $TEMP_FILE"
echo "Temporary files created:"
echo "  - $TEMP_FILE"
echo "  - $TEMP_RESULTS"
echo "  - $TEMP_SORTED"